const payload = $('子流程入口-sora').item.json.body || {};
const imageUrl = String(payload.image_url || '').trim();

if (!imageUrl) {
  throw new Error('image_url 为空，图生视频需要传 image_url');
}

const requestBody = {
  model: 'sora-2-image-to-video',
  input: {
    prompt: payload.prompt || '',
    image_urls: [imageUrl],
    aspect_ratio: payload.aspect_ratio || 'portrait',
    n_frames: String(payload.n_frames || '15'),
    remove_watermark: true
  }
};

return {
  json: {
    requestBody,
    imageUrl,
    replication_id: payload.replication_id,
    api_key: payload.api_key,
    workflow_id_for_credits: payload.workflow_id_for_credits,
    callback_url: payload.callback_url,
    admin_token: payload.admin_token,
  }
};

const payload = $('子流程入口-sora').item.json.body || {};

const requestBody = {
  model: 'sora-2-text-to-video',
  input: {
    prompt: payload.prompt || '',
    aspect_ratio: payload.aspect_ratio || 'portrait',
    n_frames: String(payload.n_frames || '15'),
    remove_watermark: true
  }
};

return {
  json: {
    requestBody,
    replication_id: payload.replication_id,
    api_key: payload.api_key,
    workflow_id_for_credits: payload.workflow_id_for_credits,
    callback_url: payload.callback_url,
    admin_token: payload.admin_token,
  }
};

function buildQS(obj) {
  return Object.entries(obj)
    .filter(([, v]) => v !== undefined && v !== null && String(v).trim() !== '')
    .map(([k, v]) => `${encodeURIComponent(k)}=${encodeURIComponent(String(v))}`)
    .join('&');
}

function cleanPrompt(raw) {
  let p = raw ?? '';
  if (Array.isArray(p)) p = p.join(' ');
  if (typeof p !== 'string') p = String(p);
  p = p.replace(/\r?\n+/g, ' ').replace(/\s{2,}/g, ' ').trim();
  const negIdx = p.indexOf('Negative prompt:');
  if (negIdx >= 0) p = p.slice(0, negIdx).trim();
  return p;
}

function normalizeAspect(v) {
  const s = String(v ?? 'portrait').trim().toLowerCase();
  if (['portrait', '9:16', '9/16'].includes(s)) return 'portrait';
  if (['landscape', '16:9', '16/9'].includes(s)) return 'landscape';
  return 'portrait';
}

function normalizeFrames(v) {
  const s = String(v ?? '15').trim();
  return (s === '10' || s === '15') ? s : '15';
}

return $input.all().map(item => {
  const json = item.json || {};
  const req = json.requestBody || {};
  const input = req.input || {};

  const prompt = cleanPrompt(input.prompt);
  if (!prompt) throw new Error('prompt 为空');

  const aspectRatio = normalizeAspect(input.aspect_ratio);
  const nFramesStr = normalizeFrames(input.n_frames);
  const imageUrls = Array.isArray(input.image_urls) ? input.image_urls.filter(Boolean) : [];
  const hasImage = imageUrls.length > 0;
  const model = hasImage ? 'sora-2-image-to-video' : 'sora-2-text-to-video';

  // kie.ai 回调到 sora_kie_callback，上下文通过 QS 传递
  const callbackBase = 'https://hooks.atomx.top/webhook/sora_kie_callback';

  const qs = buildQS({
    replication_id: json.replication_id,
    api_key: json.api_key,
    workflow_id_for_credits: json.workflow_id_for_credits,
    admin_token: json.admin_token,
    callback_url: json.callback_url,
  });

  const callBackUrl = qs ? `${callbackBase}?${qs}` : callbackBase;

  const outInput = {
    prompt,
    aspect_ratio: aspectRatio,
    n_frames: nFramesStr,
    remove_watermark: true
  };

  if (hasImage) outInput.image_urls = imageUrls;

  json.soraCreateTaskBody = {
    model,
    callBackUrl,
    input: outInput
  };

  json.requestBody = {
    model,
    input: outInput
  };

  json.debug = {
    hasImage,
    model,
    aspect_ratio: aspectRatio,
    n_frames: nFramesStr,
    callbackBase,
    callback: callBackUrl
  };

  return { json };
});

const res = $input.first().json || {};
const taskId = res.taskId || res.task_id || res.data?.taskId || res.data?.task_id ||
  (Array.isArray(res.data) ? (res.data[0]?.taskId || res.data[0]?.task_id) : undefined);

if (!taskId) throw new Error(`上一个节点里没有找到 taskId，响应为：${JSON.stringify(res).slice(0, 500)}`);

const ctx = $('清洗提示词').item.json || {};
return {
  json: {
    id: ctx.replication_id,
    taskId,
    replication_id: ctx.replication_id,
    api_key: ctx.api_key,
    workflow_id_for_credits: ctx.workflow_id_for_credits,
    admin_token: ctx.admin_token,
    callback_url: ctx.callback_url,
    startTime: Date.now()
  }
};
